mapper.select:
SELECT f.id, f.type, f.title, f.content, f.screenshot_url AS screenshotUrl, f.contact, f.submitter_id AS submitterId, u.real_name AS submitterName, f.status, f.handler_id AS handlerId, handler.real_name AS handlerName, f.handle_note AS handleNote, f.handle_time AS handleTime, f.create_time AS createTime FROM sys_feedback f LEFT JOIN sys_user u ON u.id = f.submitter_id AND u.deleted = 0 LEFT JOIN sys_user handler ON handler.id = f.handler_id AND handler.deleted = 0
f.deleted = 0
AND f.submitter_id = #{submitterId}
AND f.type = #{query.type}
AND f.status = #{query.status}
AND f.title LIKE CONCAT('%', #{query.keyword}, '%')
AND f.submitter_id = #{query.submitterId}
ORDER BY f.create_time DESC, f.id DESC
